import{$,$$,on,prefersReducedMotion}from"./utils.js";import{upgradeFloats}from"./ingredients.js";const MOODS=["paper","mist","turquoise","teal-deep","ember","ink"];const THEME_COLORS={paper:"#F4EFE6",mist:"#B6C9C6",turquoise:"#6FA29F","teal-deep":"#4C837F",ember:"#5E2320",ink:"#16211F",};let reduced=false;const DIST=window.matchMedia("(max-width: 1023.98px)").matches?0.6:1;let frontSlot="a";let timelines=new Map();let ambients=new Map();let resets=new Map();let playTimers=new Map();let enterIO=null;let loadIO=null;export function init(){reduced=prefersReducedMotion();on("dish:active",({mood})=>setMood(mood||"paper"));}
let currentMood=null;function setMood(mood){if(!MOODS.includes(mood))mood="paper";if(mood===currentMood)return;currentMood=mood;document.body.dataset.mood=mood;$("meta[name='theme-color']")?.setAttribute("content",THEME_COLORS[mood]);const back=$(`.atmo-layer[data-slot="${frontSlot === "a" ? "b" : "a"}"]`);const front=$(`.atmo-layer[data-slot="${frontSlot}"]`);back.className=`atmo-layer atmo--${mood}`;if(reduced||!window.gsap||document.visibilityState==="hidden"){back.style.opacity=1;front.style.opacity=0;}else{gsap.killTweensOf([back,front]);gsap.to(back,{opacity:1,duration:1.15,ease:"sine.inOut"});gsap.to(front,{opacity:0,duration:1.15,ease:"sine.inOut"});}
frontSlot=frontSlot==="a"?"b":"a";}
export function bindDishes(){timelines.forEach((tl)=>tl.kill());ambients.forEach((tweens)=>tweens.forEach((t2)=>t2.kill()));playTimers.forEach((t2)=>clearTimeout(t2));timelines=new Map();ambients=new Map();resets=new Map();playTimers=new Map();enterIO?.disconnect();loadIO?.disconnect();const container=$("#snap");const sections=$$("[data-animate]",container);if(!window.gsap||reduced)return;const indexOf=new Map(sections.map((s,i)=>[s,i]));sections.forEach((section)=>section.classList.add("anim-ready"));const ensure=(section)=>{if(!timelines.has(section)){timelines.set(section,section.classList.contains("dish")?buildDishTimeline(section):buildGenericTimeline(section));ambients.set(section,buildAmbient(section,indexOf.get(section)||0));}
return timelines.get(section);};enterIO=new IntersectionObserver((entries)=>{for(const entry of entries){const section=entry.target;if(entry.intersectionRatio>=0.6){const tl=ensure(section);const amb=ambients.get(section)||[];clearTimeout(playTimers.get(section));playTimers.set(section,setTimeout(()=>{tl.play(0);amb.forEach((t2)=>t2.resume());$(".dish__figure",section)?.classList.add("is-active");},120));}else if(entry.intersectionRatio>=0.15){ensure(section);}else{clearTimeout(playTimers.get(section));const tl=timelines.get(section);if(!tl)continue;tl.pause(0);resets.get(section)?.();(ambients.get(section)||[]).forEach((t2)=>t2.pause());$(".dish__figure",section)?.classList.remove("is-active");}}},{root:container,threshold:[0.15,0.6]},);sections.forEach((s)=>enterIO.observe(s));}
