function buildAmbient(section,index=0){const tweens=[];const breathe=$(".dish__breathe",section);if(breathe){tweens.push(gsap.to(breathe,{scale:1.035,duration:8+(index%5)*0.35,ease:"sine.inOut",yoyo:true,repeat:-1,paused:true,}));const figure=$(".dish__figure, .chef__figure",section);if(figure){tweens.push(gsap.to(figure,{y:-5,duration:6+(index%4)*0.45,ease:"sine.inOut",yoyo:true,repeat:-1,paused:true,}));}}
$$(".float",section).forEach((el,i)=>{tweens.push(gsap.to(el,{y:7+(i%3)*2,rotate:i%2?4:-4,duration:5+i*1.1+(index%3)*0.4,ease:"sine.inOut",yoyo:true,repeat:-1,paused:true,}));});$$(".craft-tile .ingredient-visual",section).forEach((el,i)=>{tweens.push(gsap.to(el,{rotate:i%2?3:-3,duration:6+i,ease:"sine.inOut",yoyo:true,repeat:-1,paused:true,}));});const closingMark=section.classList.contains("closing")&&$(".wordmark--closing",section);if(closingMark){tweens.push(gsap.to(closingMark,{opacity:0.82,duration:7,ease:"sine.inOut",yoyo:true,repeat:-1,paused:true,}));}
return tweens;}
let offPreload=null;export function bindImages(applyImageFn){const container=$("#snap");const imgs=$$("img[data-image]",container);const load=(img)=>{loadIO.unobserve(img);applyImageFn(img,img.dataset.image,img.dataset.dir||"assets/images/dishes/",img.dataset.sizes||undefined,);};loadIO=new IntersectionObserver((entries)=>{for(const entry of entries){if(entry.isIntersecting){load(entry.target);upgradeFloats(entry.target.closest(".screen"));}}},{root:container,rootMargin:"100% 0px"},);imgs.forEach((img)=>loadIO.observe(img));offPreload?.();offPreload=on("dish:active",({index})=>{const screens=$$(".screen",container);[screens[index],screens[index+1]].forEach((screen)=>{if(!screen)return;$$("img[data-image]",screen).forEach((img)=>{if(!img.src)load(img);});upgradeFloats(screen);});});}
export function heroEntrance(){if(!window.gsap||reduced)return;const hero=$(".hero");const tl=gsap.timeline({defaults:{ease:"power3.out"}});const add=(sel,fromVars,toVars,pos)=>{const els=$$(sel,hero);if(els.length)tl.fromTo(els,fromVars,toVars,pos);};const light=$(".hero__light",hero);if(light){tl.fromTo(light,{xPercent:-30,opacity:0},{xPercent:20,opacity:1,duration:1.6,ease:"sine.inOut"},0);gsap.to(light,{xPercent:24,duration:12,ease:"sine.inOut",yoyo:true,repeat:-1,delay:1.6});}
add(".hero__logo",{scale:1.08},{scale:1,duration:1.0,ease:"power2.out"},0.05);add(".hero__cats > *",{y:12,scale:0.94,opacity:0},{y:0,scale:1,opacity:1,duration:0.5,stagger:0.05,ease:"back.out(1.3)"},0.45);add(".swipe-hint",{opacity:0},{opacity:1,duration:0.6,ease:"power2.out"},1.2);const breathe=$(".hero__breathe",hero);if(breathe){gsap.to(breathe,{scale:1.035,duration:9,ease:"sine.inOut",yoyo:true,repeat:-1});}}